sp_widget.client_script:
function($scope, $location) {
    var c = this;

    // Navigate to persona-specific page
    c.navigateToPersona = function(personaId) {
        $location.path('/persona/' + personaId);
    };

    // Quick action navigation
    c.quickAction = function(action) {
        switch(action) {
            case 'catalog':
                $location.path('/catalog');
                break;
            case 'knowledge':
                $location.path('/kb');
                break;
            case 'requests':
                $location.path('/requests');
                break;
            case 'docs':
                $location.path('/documentation');
                break;
            case 'apis':
                $location.path('/api-catalog');
                break;
            case 'templates':
                $location.path('/templates');
                break;
            case 'tools':
                $location.path('/tools');
                break;
            case 'support':
                $location.path('/support');
                break;
        }
    };

    // Search functionality
    c.search = function() {
        if (c.searchQuery) {
            $location.path('/search').search({q: c.searchQuery});
        }
    };
}

