sp_widget.script:
(function() {
    // Server-side script
    data.user = gs.getUser();
    data.userName = data.user.getDisplayName();
    data.userInitials = data.user.getInitials();

    // Get user roles
    data.userRoles = [];
    var roles = gs.getUser().getRoles().toString().split(',');
    data.userRoles = roles;

    // Determine primary persona based on roles
    data.primaryPersona = 'developer'; // default
    if (roles.indexOf('x_ibmin_idpbob.platform_engineer') > -1) {
        data.primaryPersona = 'platform_engineer';
    } else if (roles.indexOf('x_ibmin_idpbob.sre') > -1) {
        data.primaryPersona = 'sre';
    } else if (roles.indexOf('x_ibmin_idpbob.security_engineer') > -1) {
        data.primaryPersona = 'security_engineer';
    } else if (roles.indexOf('x_ibmin_idpbob.product_owner') > -1) {
        data.primaryPersona = 'product_owner';
    } else if (roles.indexOf('x_ibmin_idpbob.servicenow_admin') > -1) {
        data.primaryPersona = 'servicenow_admin';
    }

    // Get statistics (mock data - replace with actual queries)
    data.stats = {
        activeServices: 127,
        apiEndpoints: 342,
        deployments: 89,
        incidents: 3
    };
})();
